import{_ as e,c as o,o as r,ai as a}from"./chunks/framework.TS84ywiI.js";const b=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"en/intro.md","filePath":"en/intro.md"}'),n={name:"en/intro.md"};function i(s,t,c,d,h,l){return r(),o("div",null,t[0]||(t[0]=[a('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p><a href="https://github.com/doocs" target="_blank" rel="noreferrer"><img src="https://badgen.net/badge/%3E%3E/GitHub/cyan" alt="github"></a><a href="https://gitcode.com/doocs" target="_blank" rel="noreferrer"><img src="https://badgen.net/badge/%3E%3E/GitCode/cyan" alt="gitcode"></a><a href="https://gitee.com/doocs" target="_blank" rel="noreferrer"><img src="https://badgen.net/badge/%3E%3E/Gitee/cyan" alt="gitee"></a><a href="#how-to-join"><img src="https://badgen.net/badge/organization/join%20us/cyan" alt="doocs-open-source-organization"></a><a href="https://gitter.im/doocs" target="_blank" rel="noreferrer"><img src="https://badgen.net/badge/gitter/chat/cyan" alt="gitter"></a><a href="https://github.com/doocs/doocs.github.io/blob/main/LICENSE" target="_blank" rel="noreferrer"><img src="https://badgen.net/github/license/doocs/doocs.github.io?color=green" alt="license"></a></p><p>Hello, everyone! Welcome to the <a href="https://github.com/doocs" target="_blank" rel="noreferrer">Doocs</a> Open Source community. We are currently focusing on sharing various development-related knowledge.</p><h2 id="sites" tabindex="-1">Sites <a class="header-anchor" href="#sites" aria-label="Permalink to &quot;Sites&quot;">​</a></h2><p><a href="https://doocs.org" target="_blank" rel="noreferrer">https://doocs.org</a></p><h2 id="owner" tabindex="-1">Owner <a class="header-anchor" href="#owner" aria-label="Permalink to &quot;Owner&quot;">​</a></h2><p><a href="https://github.com/yanglbme" target="_blank" rel="noreferrer">Yang Libin</a>, focus on the inner workings of web applications to build out the &quot;server-side&quot; of web applications.</p><ul><li>Wechat: YLB0109</li><li>Email: <a href="mailto:contact@yanglibin.info" target="_blank" rel="noreferrer">contact@yanglibin.info</a></li><li>GitHub: <a href="https://github.com/yanglbme" target="_blank" rel="noreferrer">https://github.com/yanglbme</a></li><li>GitCode: <a href="https://gitcode.com/yanglbme" target="_blank" rel="noreferrer">https://gitcode.com/yanglbme</a></li><li>Gitee: <a href="https://gitee.com/yanglbme" target="_blank" rel="noreferrer">https://gitee.com/yanglbme</a></li></ul><h2 id="projects" tabindex="-1">Projects <a class="header-anchor" href="#projects" aria-label="Permalink to &quot;Projects&quot;">​</a></h2><p>Doocs now has the following hot projects:</p><table tabindex="0"><thead><tr><th>#</th><th>Project</th><th>Description</th><th>Popularity</th></tr></thead><tbody><tr><td>1</td><td><a href="https://github.com/doocs/advanced-java" target="_blank" rel="noreferrer">advanced-java</a></td><td>Core interview questions &amp; answers for experienced Java(Backend) developers.</td><td><img src="https://badgen.net/github/stars/doocs/advanced-java" alt=""> <br><img src="https://badgen.net/github/forks/doocs/advanced-java" alt=""></td></tr><tr><td>2</td><td><a href="https://github.com/doocs/leetcode" target="_blank" rel="noreferrer">leetcode</a></td><td>LeetCode solutions in any programming language.</td><td><img src="https://badgen.net/github/stars/doocs/leetcode" alt=""> <br><img src="https://badgen.net/github/forks/doocs/leetcode" alt=""></td></tr><tr><td>3</td><td><a href="https://github.com/doocs/source-code-hunter" target="_blank" rel="noreferrer">source-code-hunter</a></td><td>Source code analysis of frameworks and components.</td><td><img src="https://badgen.net/github/stars/doocs/source-code-hunter" alt=""> <br><img src="https://badgen.net/github/forks/doocs/source-code-hunter" alt=""></td></tr><tr><td>4</td><td><a href="https://github.com/doocs/jvm" target="_blank" rel="noreferrer">jvm</a></td><td>A summary of the underlying principles of Java Virtual Machine.</td><td><img src="https://badgen.net/github/stars/doocs/jvm" alt=""> <br><img src="https://badgen.net/github/forks/doocs/jvm" alt=""></td></tr><tr><td>5</td><td><a href="https://github.com/doocs/coding-interview" target="_blank" rel="noreferrer">coding-interview</a></td><td>A collection of interview questions for programmers. The main contents include ‘Coding Interviews: Questions, Analysis and Solutions’, ‘Beauty of Programming’, etc.</td><td><img src="https://badgen.net/github/stars/doocs/coding-interview" alt=""> <br><img src="https://badgen.net/github/forks/doocs/coding-interview" alt=""></td></tr><tr><td>6</td><td><a href="https://github.com/doocs/md" target="_blank" rel="noreferrer">md</a></td><td>An online wechat markdown editor.</td><td><img src="https://badgen.net/github/stars/doocs/md" alt=""> <br><img src="https://badgen.net/github/forks/doocs/md" alt=""></td></tr><tr><td>7</td><td><a href="https://github.com/doocs/technical-books" target="_blank" rel="noreferrer">technical-books</a></td><td>Awesome programming books list.</td><td><img src="https://badgen.net/github/stars/doocs/technical-books" alt=""> <br><img src="https://badgen.net/github/forks/doocs/technical-books" alt=""></td></tr></tbody></table><h2 id="how-to-join" tabindex="-1">How to join <a class="header-anchor" href="#how-to-join" aria-label="Permalink to &quot;How to join&quot;">​</a></h2><blockquote><p><em>If you want to go fast, go alone. If you want to go far, go together.</em></p></blockquote><p>I believe many of you have a deep understanding that participating in open source projects is very helpful for personal growth. If you love open source or you are curious about it, join Doocs, work with us, maintain our projects and grow together. You can join us in the following two ways:</p><ul><li>Comment on the <a href="https://github.com/doocs/doocs.github.io/issues" target="_blank" rel="noreferrer">relevant issue</a> on GitHub to express interest in joining the community.</li><li>Send an email to <a href="mailto:admin@doocs.org?Subject=Join%20the%20Doocs%20Open%20Source%20organization" target="_blank" rel="noreferrer">admin@doocs.org</a> with the GitHub ID to request to join the community.</li></ul><p>By default, your Doocs membership will be hidden from view aftering joining us. If you&#39;d like to display the organization icon in your profile, you can switch from &quot;Private&quot; to &quot;Public&quot; here: <a href="https://github.com/orgs/doocs/people" target="_blank" rel="noreferrer">https://github.com/orgs/doocs/people</a>. We also recommend setting it to Public.</p><p>Once a member of the community, the member can fork any project of interest and make modifications, and then submit a pull request for review. If the submission is deemed to be in compliance with the project&#39;s standards, the member may be added as a collaborator to the project.</p><p>It is worth noting that initially, new members may not have direct write access to the projects, as the maintainers need to assess the quality of the submissions. Therefore, it is recommended that new members make submissions regularly to become familiar with the GitHub workflow and to improve their submissions over time.</p><p>You can refer to this <a href="https://github.com/firstcontributions/first-contributions/blob/master/README.md" target="_blank" rel="noreferrer">article</a> if you are a new open-source contributor.</p><p>Overall, the Doocs community seems to be a valuable resource for programmers interested in learning about internet backend development and open-source development. The community offers various resources and projects that can help programmers improve their skills and contribute to the open-source community.</p><p>Doocs is looking forward to your joining.</p><h2 id="contributors" tabindex="-1">Contributors <a class="header-anchor" href="#contributors" aria-label="Permalink to &quot;Contributors&quot;">​</a></h2><p>This organization exists thanks to all the people who contribute.</p><p><a href="https://github.doocs.org" target="_blank"><img src="https://raw.githubusercontent.com/doocs/.github/main/images/contributors.png"></a></p><h2 id="contact" tabindex="-1">Contact <a class="header-anchor" href="#contact" aria-label="Permalink to &quot;Contact&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:center;"><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/images/qrcode-for-doocs.png" alt="QRCode1"></th><th style="text-align:center;"><img src="https://cdn-doocs.oss-cn-shenzhen.aliyuncs.com/gh/doocs/images/qrcode-for-yanglbme.png" alt="QRCode2"></th></tr></thead></table>',26)]))}const u=e(n,[["render",i]]);export{b as __pageData,u as default};
